const input = $input.first().json;
const word = (input.word || '').trim();

if (!word) {
  return [{ json: { result: 'Error: No word provided. Please specify a word to look up.' } }];
}

try {
  const data = await helpers.httpRequest({
    method: 'GET',
    url: 'https://api.dictionaryapi.dev/api/v2/entries/en/' + encodeURIComponent(word),
    returnFullResponse: true
  });

  const entries = typeof data.body === 'string' ? JSON.parse(data.body) : data.body;

  if (!Array.isArray(entries) || entries.length === 0) {
    return [{ json: { result: 'Word not found: ' + word } }];
  }

  const entry = entries[0];
  let r = 'Word: ' + (entry.word || word) + '\n';

  if (entry.phonetic) {
    r += 'Phonetic: ' + entry.phonetic + '\n';
  } else if (entry.phonetics && entry.phonetics.length > 0) {
    const ph = entry.phonetics.find(p => p.text);
    if (ph) r += 'Phonetic: ' + ph.text + '\n';
  }

  r += '\n';

  if (entry.meanings && entry.meanings.length > 0) {
    for (const meaning of entry.meanings) {
      r += '--- ' + (meaning.partOfSpeech || 'unknown') + ' ---\n';
      const defs = (meaning.definitions || []).slice(0, 3);
      for (let i = 0; i < defs.length; i++) {
        r += (i + 1) + '. ' + defs[i].definition + '\n';
        if (defs[i].example) {
          r += '   Example: "' + defs[i].example + '"\n';
        }
      }
      r += '\n';
    }
  }

  return [{ json: { result: r.trim() } }];
} catch (e) {
  if (e.statusCode === 404 || (e.message && e.message.includes('404'))) {
    return [{ json: { result: 'Word not found: "' + word + '". Please check the spelling and try again.' } }];
  }
  return [{ json: { error: 'Dictionary lookup failed: ' + e.message } }];
}
